<template>
  <div>
    <div class="searchDiv">
      <table class="tableClass01">
        <tr>
          <td class="tdClass01">使用系統代碼</td>
          <td class="tdClass02"><input type="text" v-model="getSysCod"></td>
          <td class="tdClass01">管控表格名稱</td>
          <td class="tdClass02"><input type="text" v-model="getCtlTable" size="30"></td>
          <td class="tdClass01">管控欄位名稱</td>
          <td class="tdClass02"><input type="text" v-model="getctlFldNam" size="30"></td>
        </tr>
        <tr>
          <td class="tdClass01">定義代碼</td>
          <td class="tdClass02">
            <input type="text" v-model="getDefCod" size="40">
            <span class="spanClass01">可模糊查詢：關鍵字％</span>
          </td>
          <td class="tdClass01">定義名稱</td>
          <td class="tdClass02">
            <input type="text" v-model="getDefNam" size="50">
            <span class="spanClass01">可模糊查詢：關鍵字％</span>
          </td>
          <td class="tdClass01">異動碼</td>
          <td class="tdClass02">
            <select v-model="getTsc">
              <option v-for="(tscValue, tscKey) in tscArr" :key="tscKey" :value="tscKey">{{ tscValue }}</option>
            </select>
          </td>
        </tr>
      </table>
    </div>
    <div class="searchEnter">
      <input type="button" value="查 詢" @click="searchData">
      &nbsp;
      <input type="button" value="匯 出">
    </div>
    <div class="dataContainer">
      <table class="tableClass02">
        <tr>
          <td class="tdClass03">#</td>
          <td class="tdClass03">操作</td>
          <td class="tdClass03">使用系統代碼</td>
          <td class="tdClass03">管控表格名稱</td>
          <td class="tdClass03">管控欄位名稱</td>
          <td class="tdClass03">定義代碼</td>
          <td class="tdClass03">定義名稱</td>
          <td class="tdClass03">異動碼</td>
          <td class="tdClass03">異動人員</td>
          <td class="tdClass03">異動人員</td>
        </tr>
        <tr v-for="(dataItem, dataKey) in getList" :key="dataKey">
          <td class="tdClass04" :class="{'blue': (dataKey + 1) % 2 == 0}">{{ dataKey + 1 }}</td>
          <td class="tdClass04" :class="{'blue': (dataKey + 1) % 2 == 0}"></td>
          <td class="tdClass04" :class="{'blue': (dataKey + 1) % 2 == 0}">{{ dataItem.SYS_COD }}</td>
          <td class="tdClass04" :class="{'blue': (dataKey + 1) % 2 == 0}">{{ dataItem.CTL_TABLE }}</td>
          <td class="tdClass04" :class="{'blue': (dataKey + 1) % 2 == 0}">{{ dataItem.CTL_FLD_NAM }}</td>
          <td class="tdClass04" :class="{'blue': (dataKey + 1) % 2 == 0}">{{ dataItem.DEF_COD }}</td>
          <td class="tdClass04" :class="{'blue': (dataKey + 1) % 2 == 0}">{{ dataItem.DEF_NAM }}</td>
          <td class="tdClass04" :class="{'blue': (dataKey + 1) % 2 == 0}">{{ dataItem.STS }}</td>
          <td class="tdClass04" :class="{'blue': (dataKey + 1) % 2 == 0}">{{ dataItem.RTP }}</td>
          <td class="tdClass04" :class="{'blue': (dataKey + 1) % 2 == 0}">{{ dataItem.RTT }}</td>
        </tr>
      </table>
    </div>
  </div>
</template>

<script>
export default {
  name: 'Search',
  data () {
    return {
      getSysCod: '',
      getCtlTable: '',
      getctlFldNam: '',
      getDefCod: '',
      getDefNam: '',
      getTsc: '',
      tscArr: {'': '全部', 'A': '新增', 'D': '失效'},
      getList: []
    }
  },
  methods: {
    searchData () {
      var vm = this
      if (vm.getSysCod && vm.getCtlTable && vm.getctlFldNam && vm.getDefCod) {
        this.getApiData()
      } else {
        alert('查詢條件不可空白')
      }
    },
    async getApiData () {
      var vm = this
      vm.getList = []
      // START:呼叫TAG-------------------------------------------
      var tag = 'pvt.ns.getGenDefList'
      let param = {
        wb_base64: '0',
        wb_big5: '0',
        encode: 'N',
        typ: '3',
        SYS_COD: vm.getSysCod,
        TABLE: vm.getCtlTable,
        FLD_NAM: vm.getctlFldNam,
        DEF_COD: vm.getDefCod
      }
      let result = await this.$gows.callWS(tag, param)
      // END:呼叫TAG-------------------------------------------
      console.log(result)
      if (result.sts === '000000') {
        // console.log('呼叫WS成功===>')
        let getVal = result.val
        for (var index in getVal) {
          if (vm.getTsc) {
            if (vm.getTsc !== getVal[index]['STS']) {
              continue
            }
          }
          // set資料array
          vm.getList.push({
            'GD_NO': getVal[index]['GD_NO'],
            'SYS_COD': getVal[index]['SYS_COD'],
            'CTL_TABLE': getVal[index]['CTL_TABLE'],
            'CTL_FLD_NAM': getVal[index]['CTL_FLD_NAM'],
            'DEF_COD': getVal[index]['DEF_COD'],
            'DEF_NAM': getVal[index]['DEF_NAM'],
            'STS': getVal[index]['STS'] + '：' + vm.tscArr[getVal[index]['STS']],
            'RTP': getVal[index]['RTP'],
            'RTT': getVal[index]['RTT']
          })
        }
      } else {
        console.log(result.sts, result.msg)
      }
    }
  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
input[type='text'], select {
  border: 1px solid rgb(182, 181, 181);
  border-radius: 6px;
}
.searchEnter {
  padding: 0.25rem;
  text-align: center;
}
input[type='button'] {
 border-radius: 15px;
 border: 1px solid rgb(38, 160, 139);
 font-size: 1.2rem;
 padding: 0.15rem 1.2rem;
 background-color:rgb(38, 160, 139);
 color: #FFFFFF;
 font-weight: bold;
}
input[type='button']:hover {
  background-color:rgb(250, 242, 168);
  color: rgb(38, 160, 139);
}
.tableClass01 {
  background-color:#FFFFFF;
  width: 100%;
  border: 1px solid #FFFFFF;
  border-radius: 10px;
  font-family: 'Microsoft JhengHei';
  color:darkslategrey;
}
.tableClass02 {
  background-color:#FFFFFF;
  width: 100%;
  border: 1px solid #FFFFFF;
  font-family: 'Microsoft JhengHei';
  font-weight: bold;
  color:darkslategrey;
  text-align: center;
}
.tdClass01 {
  background-color:rgb(190, 233, 233);
  padding: 0.2rem;
  border: 1px solid rgb(243, 253, 253);
  text-align: center;
  font-weight: bold;
}
.tdClass02 {
  background-color:rgb(235, 243, 243);
  border: 1px solid rgb(243, 253, 253);
}
.tdClass03 {
  background-color:rgb(134, 218, 218);
  padding: 0.2rem;
  border: 2px solid rgb(243, 253, 253);
  text-align: center;
  font-weight: bold;
}
.tdClass04 {
  background-color:rgb(241, 241, 241);
  padding: 0.2rem;
  border: 2px solid rgb(243, 253, 253);
  text-align: center;
  font-weight: bold;
}
.tdClass04.blue {
  background-color:rgb(219, 219, 219);
}
.spanClass01 {
  font-size: 1rem;
  color:rgb(123, 167, 182);
}
</style>



