<template>
  <div>
    <div class="hello">
      <h1>{{ msg }}</h1>
    </div>
    <div>
      <ul class="nav nav-tabs">
        <li class="nav-item">
          <router-link class="nav-link" :class="{'active': $route.path === '/Search'}" to="/Search">查詢</router-link>
        </li>
        <li class="nav-item">
          <router-link class="nav-link" :class="{'active': $route.path === '/Add'}" to="/Add">新增</router-link>
        </li>
      </ul>
    </div>
    <div>
      <div class="viewContainer">
        <router-view></router-view>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  name: 'Home',
  data () {
    return {
      msg: '欄位定義維護建檔'
    }
  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
.hello {
  margin-left: 0.8rem;
  margin-top: 1rem;
}
.viewContainer {
  margin-left: 0.8rem;
  margin-top: 0.5rem;
}
.nav-link {
  border-color:rgb(223, 223, 223);
  /* color: #FFFFFF; */
}
.nav-link.active {
  background-color:rgb(37, 175, 129);
  color: #FFFFFF;
}
h1, h2 {
  font-weight: normal;
}
ul {
  list-style-type: none;
  padding: 0;
}
li {
  display: inline-block;
  margin: 0 10px;
}
a {
  color: #42b983;
}
</style>



